var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_DUMMY","text":{"KOREA":"편지가 하나 왔습니다.","JPN":"手紙が届きました。","ENG":"Something came in the mail.","TWN":"有一封信。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_DUMMY","text":{"KOREA":"편지? 전자 메일을 말하는 건가?","JPN":"手紙？　メールのことを言っているのか？","ENG":"Mail? You mean e-mail?","TWN":"信？是電子信件嗎？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_DUMMY","text":{"KOREA":"아니요. 손으로 쓴 편지입니다.","JPN":"いえ、手書きの手紙です。","ENG":"No. A hand-written letter.","TWN":"不是，是親筆寫的信。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_DUMMY","text":{"KOREA":"손으로? 요즘 시대에도 그런 걸 쓰는 사람이 남아있었군.","JPN":"手書き？　今の時代でこんなものを書く人が残っていたとは。","ENG":"Hand-written? I had no idea that people still write letters in the modern age.","TWN":"親筆？現在還有人會親筆寫信喔？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_DUMMY","text":{"KOREA":"…아니, 잠깐. 이 대화 전에도 나눈 기억이 있는 것 같은데.","JPN":"…いや、待て。この会話はなんだか聞き覚えがあるような。","ENG":"... Hang on. I think we had this conversation before.","TWN":"等等…這段對話怎麼有種既視感？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_DUMMY","text":{"KOREA":"맞습니다. 전에 편지를 보낸 아카데미 중등부의 양하림 학생이더군요.","JPN":"はい、前にも手紙を送ってきた、アカデミー中等部のホシノ・ウサギという学生からの手紙です。","ENG":"You're right. It's from the same student. Yang Harim, the junior high student in the Academy.","TWN":"沒錯，就是以前有寄過信的楊夏琳學生。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_DUMMY","text":{"KOREA":"이번에도 동아리 활동을 위한 금전적 지원 얘기가 담겨있던가?","JPN":"今回もサークル活動に必要な金銭的支援を求める内容か？","ENG":"Does she want more financial support for her club?","TWN":"這次也是寫信來要錢的嗎？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_DUMMY","text":{"KOREA":"아뇨. 편지 서두에 지원금은 늘 감사하다고 적혀 있습니다.","JPN":"いいえ。補助金については、手紙の冒頭にいつも感謝していると書かれています。","ENG":"No. Speaking of which, she thanked you for the funds in the beginning of her letter.","TWN":"不，在信的開頭寫著：謝謝您一直以來的經費贊助。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_DUMMY","text":{"KOREA":"그럼 무슨 일이지? 설마… 청소년 근로기준을 지키지 않은 건가?","JPN":"別件か？　まさか……年少者の労働基準規則違反か？","ENG":"Okay, then what is it? We didn't violate any child labor laws, did we?","TWN":"她想幹麼？該不會…我們有違反青少年勞動法嗎？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_DUMMY","text":{"KOREA":"제가 준법정신이 투철한 덕분에 사장님께서 아직 멀쩡히 살아계시다는 걸 모르시는 모양이네요.","JPN":"私が規範意識を持っているおかげで、社長がまだ健在だということに気付いていないようですね。","ENG":"In case you didn't notice, you're still alive because I'm a law-abiding citizen.","TWN":"看來您還不知道，您現在之所以能在這裡和我對話，完全是託我奉公守法的福。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_DUMMY","text":{"KOREA":"폭력은… 결사 반대라네.","JPN":"暴力は……絶対に反対だぞ。","ENG":"I vehemently oppose the use of violence.","TWN":"我反對…暴力！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_DUMMY","text":{"KOREA":"동아리에서 주인 없는 고양이를 키워줄 사람을 찾고 있다고 합니다.","JPN":"サークルで飼い主のいない猫の里親を探しているらしいです。","ENG":"Her club is looking for a new owner for a stray cat.","TWN":"她們的社團正在尋找可以養貓的人。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_DUMMY","text":{"KOREA":"……주인을 찾지 못하면 동아리의 입장이 곤란해지겠군.","JPN":"……里親が見つからないとサークルとして困るんだろうな。","ENG":"... It'll have to find someone soon, or it'll be in trouble.","TWN":"……找不到主人的話，社團可能面子不保吧？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_DUMMY","text":{"KOREA":"네. 아카데미 안에서 맡아줄 사람을 직접 찾아다녀봤지만, 모두 실패했다더군요.","JPN":"はい。アカデミーでも募集したようですが、失敗したそうです。","ENG":"Yes. It's been looking everywhere within the Academy, but to no avail.","TWN":"是的，雖然已經在學院內打聽過合適的人選，但似乎都無疾而終。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_DUMMY","text":{"KOREA":"자네도 꽤나 신경 쓰고 있지 않나? 그냥 못 본 척해도 나무랄 사람은 없을 텐데 말이야.","JPN":"君もかなり気になっているんだね。\\nこんな案件は見て見ぬふりをしても、誰一人責める人はいないだろうに。","ENG":"I can tell you're worried. But no one will blame you even if you ignore it.","TWN":"你好像也有在關心這件事嘛？就算裝作沒看到也沒人會怪你的。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_DUMMY","text":{"KOREA":"혹시 고양이에 관심이 있는 건가?","JPN":"もしかして、猫に興味があるのか？","ENG":"Are you interested in the cat?","TWN":"還是你對貓有興趣？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_DUMMY","text":{"KOREA":"글쎄요. 귀여운 고양이긴 합니다만, 동물에게 애정이나 주고 있을 만큼 감성적이고 여유로운 입장은 아니라서 말이죠.","JPN":"さあ。可愛いのは認めますが、動物に愛情を注ぐほど余裕のある立場ではないですから。","ENG":"I don't know. He's a cute cat, but I don't have time or the mental state to take care of animals at the moment.","TWN":"這個嘛…貓咪可愛是可愛，但養貓不是給牠吃而已，還要陪伴牠，對牠的生命負責任。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_DUMMY","text":{"KOREA":"사진도 있으니 확인해보시죠.","JPN":"写真もありますが、ご覧になりますか。","ENG":"I've got his photos. You can take a look.","TWN":"這邊有照片，您要看一下嗎？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_DUMMY","text":{"KOREA":"길 잃은 고양이라고 해서 경계심 많은 모습일 줄 알았는데, 온순해 보이는군.","JPN":"迷い猫なら警戒心が強いと思ったのだが、大人しく見えるな。","ENG":"He doesn't look like other stray cats that are highly irritable.","TWN":"上面說是迷路的貓，我還以為會對人有戒心，沒想到看起來很乖呢！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};